import React, { useEffect, useState } from 'react';
import { GetSeasons } from "../services/season-service";
import { Season } from "../objects/season";
import SeasonCard from "../atoms/card/season-card";
import { useNavigate } from "react-router-dom";

const Home = () => {
    
    const navigate = useNavigate();
    const [data, setData] = useState<Season[] | null>(null);

    useEffect(() => {
        GetSeasons().then(data => setData(data));
    }, []);

    const handleClick = (seasonId : any) => navigate('/Fixtures/' + seasonId);

    return(
        <>
            {/* <h3>Tigers Results</h3>
            <FixtureList fixturesToShow={TigersFixtures}></FixtureList>   
            <SeasonSummary fixtures={TigersFixtures}/> */}
            <div className="row">
                {   data ? data.map((item) => (                        
                        <SeasonCard key={item.id} season={item} handleClick={handleClick} > </SeasonCard>
                    )) : <p>Loading...</p>}
            </div>
        </>
    )
}
export default Home;
